import{_ as t,o,c as n,ae as r}from"./chunks/framework.BGHOrOyn.js";const m=JSON.parse('{"title":"Open Vehicles documentation","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/vehicle-tracking/open-vehicles-documentation.md","filePath":"obd2/vehicle-tracking/open-vehicles-documentation.md"}'),i={name:"obd2/vehicle-tracking/open-vehicles-documentation.md"};function a(l,e,s,c,h,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="open-vehicles-documentation" tabindex="-1">Open Vehicles documentation <a class="header-anchor" href="#open-vehicles-documentation" aria-label="Permalink to &quot;Open Vehicles documentation&quot;">​</a></h1><h2 id="introduction¶" tabindex="-1">Introduction¶ <a class="header-anchor" href="#introduction¶" aria-label="Permalink to &quot;Introduction¶&quot;">​</a></h2><p>The OVMS is an <strong>all open source</strong> vehicle remote monitoring, diagnosis and control system.</p><p>The system provides <strong>live monitoring</strong> of vehicle metrics like state of charge, temperatures, tyre pressures and diagnostic fault conditions. It will <strong>alert</strong> you about critical conditions and events like a charge abort, battery cell failure or potential theft. Depending on the vehicle integration it allows you to <strong>take control</strong> over the charge process, climate control, tuning parameters of the engine and more. OVMS developers are enthusiasts trying hard to provide as <strong>detailed information</strong> about the internals of a vehicle as possible.</p><p>While most new vehicles now include some kind of remote control system, very few allow deep insight, some will not work in all regions and none will give you <strong>control over your personal data</strong>. The OVMS fills that gap, and also enables you to add all these features to existing vehicles of any kind.</p><p>The OVMS can also be used for <strong>fleet monitoring</strong>. It allows a fleet manager to not only track the vehicle locations but also to monitor the vehicle’s vitals, remotely check for fault conditions, offer services like automatic preheating for users and take active control in case of abusive use. As the system is open source and fully scriptable, it can easily integrate custom access and control systems.</p><p>For <strong>developers and technicians</strong>, the OVMS includes a range of CAN tools including multiple logging formats, a configurable OBD2 translator, a DBC decoder, a reverse engineering toolkit and a CANopen client. The module provides SSH access and WebSocket streaming and can stream and inject CAN frames via TCP. Both the module and the web frontend can be customized by plugins. The module has three builtin CAN buses and <a href="https://github.com/mjuhanne/OVMS-SWCAN" target="_blank" rel="noreferrer">can be extended by a fourth one</a>.</p><p>The <strong>OVMS base component</strong> is a small and inexpensive hardware module that connects to the vehicle <strong>OBD2</strong> port. The standard kit includes a 3G modem to provide <strong>GSM</strong> connectivity and <strong>GPS</strong> and comes with a ready-to-use <a href="https://hologram.io/" target="_blank" rel="noreferrer">Hologram.io</a> SIM card. The US kit has been <strong>FCC certified</strong>, the EU kit <strong>CE certified</strong>.</p><p>The module provides a <strong>built-in Web App</strong> user interface and remote control via native cellphone Apps available for <strong>Android</strong> and <strong>iOS</strong>. It integrates into home/process automation systems via <strong>MQTT</strong> and provides data logging to SD card and to a server.</p><h3 id="vehicle-support¶" tabindex="-1">Vehicle Support¶ <a class="header-anchor" href="#vehicle-support¶" aria-label="Permalink to &quot;Vehicle Support¶&quot;">​</a></h3><ul><li><em>Native Integration</em><ul><li>Chevrolet Volt / Opel Ampera</li><li>Chevrolet Bolt EV / Opel Ampera-e</li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_bmwi3/docs/index.html" target="_blank" rel="noreferrer">BMW i3 / i3s</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_fiat500/docs/index.html" target="_blank" rel="noreferrer">Fiat 500e</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_hyundai_ioniqvfl/docs/index.html" target="_blank" rel="noreferrer">Hyundai Ioniq vFL</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_jaguaripace/docs/index.html" target="_blank" rel="noreferrer">Jaguar Ipace</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_kianiroev/docs/index.html" target="_blank" rel="noreferrer">Kia e-Niro / Hyundai Kona</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_kiasoulev/docs/index.html" target="_blank" rel="noreferrer">Kia Soul EV</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_maxus_edeliver3/docs/index.html" target="_blank" rel="noreferrer">Maxus eDeliver 3</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_mercedesb250e/docs/index.html" target="_blank" rel="noreferrer">Mercedes-Benz B250E</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_mgev/docs/index.html" target="_blank" rel="noreferrer">MG ZS EV</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_mitsubishi/docs/index.html" target="_blank" rel="noreferrer">Mitsubishi Trio (i-MiEV et al)</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_nissanleaf/docs/index.html" target="_blank" rel="noreferrer">Nissan Leaf / e-NV200</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_renaulttwizy/docs/index.html" target="_blank" rel="noreferrer">Renault Twizy</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_renaultzoe/docs/index.html" target="_blank" rel="noreferrer">Renault Zoe / Kangoo</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_smarted/docs/index.html" target="_blank" rel="noreferrer">Smart ED Gen.3</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_smarteq/docs/index.html" target="_blank" rel="noreferrer">Smart ED/EQ Gen.4 (453)</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_teslamodels/docs/index.html" target="_blank" rel="noreferrer">Tesla Model S</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_teslaroadster/docs/index.html" target="_blank" rel="noreferrer">Tesla Roadster</a></li><li>Think City</li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_toyotarav4ev/docs/index.html" target="_blank" rel="noreferrer">Toyota RAV4 EV</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_vweup/docs/index.html" target="_blank" rel="noreferrer">VW e-Up</a></li></ul></li><li><em>General Support</em><ul><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_dbc/docs/index.html" target="_blank" rel="noreferrer">DBC File Based</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_track/docs/index.html" target="_blank" rel="noreferrer">GPS Tracking</a></li><li><a href="https://docs.openvehicles.com/en/latest/components/vehicle_obdii/docs/index.html" target="_blank" rel="noreferrer">OBD-II Standard</a></li><li>Zeva BMS</li></ul></li></ul><h3 id="links¶" tabindex="-1">Links¶ <a class="header-anchor" href="#links¶" aria-label="Permalink to &quot;Links¶&quot;">​</a></h3><ul><li><em>User Resources</em><ul><li><em>User and Developer Guides: (hint: version selection in left menu at the bottom)</em><ul><li><a href="https://docs.openvehicles.com/en/stable/" target="_blank" rel="noreferrer">Stable release (OTA version “main”)</a></li><li><a href="https://docs.openvehicles.com/en/latest/" target="_blank" rel="noreferrer">Latest nightly build (OTA version “edge”)</a></li></ul></li><li><a href="https://www.openvehicles.com/forum" target="_blank" rel="noreferrer">User Support Forum</a></li><li><a href="https://play.google.com/store/apps/details?id=com.openvehicles.OVMS&amp;hl=en_US" target="_blank" rel="noreferrer">Android App</a></li><li><a href="https://apps.apple.com/us/app/open-vehicles/id490098531" target="_blank" rel="noreferrer">iOS App</a></li></ul></li><li><em>Distributors</em><ul><li><a href="https://www.fasttech.com/search?ovms" target="_blank" rel="noreferrer">FastTech (global)</a></li><li><a href="https://medlockandsons.com/product/ovms-v3/" target="_blank" rel="noreferrer">Medlock &amp; Sons (North America)</a></li><li><a href="https://shop.openenergymonitor.com/ovms/" target="_blank" rel="noreferrer">OpenEnergyMonitor (UK/Europe)</a></li></ul></li><li><em>Servers</em><ul><li><a href="https://www.openvehicles.com/" target="_blank" rel="noreferrer">Asia-Pacific</a></li><li><a href="https://dexters-web.de/" target="_blank" rel="noreferrer">Germany/Europe</a></li></ul></li><li><em>Developers</em><ul><li><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0" target="_blank" rel="noreferrer">Developer Guide</a></li><li><a href="http://lists.openvehicles.com/mailman/listinfo/ovmsdev" target="_blank" rel="noreferrer">Developer Mailing List &amp; Archive</a></li><li><a href="https://github.com/openvehicles/Open-Vehicle-Server" target="_blank" rel="noreferrer">Server Source</a></li><li><a href="https://github.com/openvehicles/Open-Vehicle-Android" target="_blank" rel="noreferrer">Android App Source</a></li><li><a href="https://github.com/openvehicles/Open-Vehicle-iOS" target="_blank" rel="noreferrer">iOS App Source</a></li></ul></li></ul><h3 id="hardware¶" tabindex="-1">Hardware¶ <a class="header-anchor" href="#hardware¶" aria-label="Permalink to &quot;Hardware¶&quot;">​</a></h3><ul><li><a href="https://github.com/openvehicles/Open-Vehicle-Monitoring-System-3/tree/master/vehicle/hardware" target="_blank" rel="noreferrer">Module Schematics and PCB Layouts</a></li><li><strong>Base Module (v3.0-3.3)</strong><ul><li>Black injection-moulded plastic enclosure, approximately 99x73x29 mm excl. plugs</li><li>ESP32 WROVER processor (16MB flash, 4MB SPI RAM, 520KB SRAM, dual core 160/240MHz Xtensa LX6 processor)</li><li>WIFI 802.11 b/g/n</li><li>Bluetooth v4.2 BR/EDR and BLE</li><li>3x CAN buses</li><li>1x Micro USB connector (for flash download and serial console)</li><li>1x Micro SD card slot</li><li>1x Internal expansion slot</li><li>8x EGPIO, 2x GPIO</li><li>1x GSM antenna connector</li><li>1x GPS antenna connector</li><li>1x DB9 vehicle connector</li><li>1x DB26 expansion connector</li></ul></li><li><strong>Modem Module v3.0-3.2</strong><ul><li>US edition is SIM5360A (Dual-Band UMTS/HSPA+ 850/1900MHz, Quad-Band GSM/GPRS/EDGE 850/900/1800/1900MHz)</li><li>EU edition is SIM5360J(E) (Dual-Band UMTS/HSPA+ 900/2100MHz, Quad-Band GSM/GPRS/EDGE 850/900/1800/1900MHz)</li><li>3G (EV-DO/HSPA+) dual band modem</li><li>Includes 2G (GSM/GPRS) and 2.5G (EDGE) quad band</li><li>GPS/GNSS</li><li>Nano (4FF) SIM slot</li><li>HOLOGRAM.IO nano sim included (can be exchanged if necessary)</li></ul></li><li><strong>Modem Module v3.3</strong><ul><li>World edition: SIM7600G (Multi-Band LTE-FDD/LTE-TDD/HSPA+ and GSM/GPRS/EDGE)</li><li>4G (LTE-FDD/LTE-TDD) multi band modem</li><li>Includes 3G (EV-DO/HSPA+), 2G (GSM/GPRS) and 2.5G (EDGE) quad band</li><li>GPS/GNSS</li><li>Nano (4FF) SIM slot</li><li>HOLOGRAM.IO nano sim included (can be exchanged if necessary)</li></ul></li></ul><h4 id="extensions¶" tabindex="-1">Extensions¶ <a class="header-anchor" href="#extensions¶" aria-label="Permalink to &quot;Extensions¶&quot;">​</a></h4><p>The external DB26 DIAG connector provides access to the three CAN buses and offers some free extension ports. The internal PCB expansion connector allows stacked additions of further modules and serves for routing GPIO ports to the external DIAG connector. See schematics for details.</p><p>A very nice first extension module has been developed by Marko Juhanne: <a href="https://github.com/mjuhanne/OVMS-SWCAN" target="_blank" rel="noreferrer">OVMS-SWCAN</a></p><p>If you plan on developing a hardware extension or just want to do some custom adaptations, have a look at our prototyping PCB kit. It’s available in packs of 3 PCBs and includes headers and mounting material:</p><p>If the kit isn’t available at the distributors, please contact Mark Webb-Johnson <a href="mailto:mark%40webb-johnson.net" target="_blank" rel="noreferrer">mark@webb-johnson.net</a>.</p><h3 id="development-and-contributions¶" tabindex="-1">Development and Contributions¶ <a class="header-anchor" href="#development-and-contributions¶" aria-label="Permalink to &quot;Development and Contributions¶&quot;">​</a></h3><p><strong>New developers are very welcome on any part of the system, and we will gladly provide any help needed to get started.</strong></p><p>The purpose of this project is to get the community of vehicle hackers and enthusiasts to be able to expand the project. We can’t do it all, and there is so much to do. What we are doing is providing an affordable and flexible base that the community can work on and extend.</p><p>Everything is open, and APIs are public. Other car modules can talk to the server, and other Apps can show the status and control the car. This is a foundation that others hopefully will interface to and and build upon.</p><p><strong>If you’d like to contribute, please accept our code of conduct:</strong></p><ul><li>Introduce yourself on the developer mailing list</li><li>Be kind &amp; polite</li><li>Understand the framework concepts</li><li>Ask if you need help</li><li>Present your plans if in doubt</li><li>Write decent code</li><li>If you extend modules, stick to their code style</li><li>Write brief but descriptive commit comments</li><li>Add user level descriptions to the change history</li><li>Provide documentation in the user guide</li><li>Use pull requests to submit your code for inclusion</li></ul><p><strong>A note on pull requests:</strong></p><p>Pull requests shall focus on one specific issue / feature / vehicle at a time and shall only mix vehicle specific changes with framework changes if they depend on each other. If changes are not or only loosely related, split them into multiple PRs (just as you would do with commits).</p><p>Usage hint: create a branch for each pull request, include only those commits in that branch (by cherry-picking if necessary) that shall be included in the pull request. That way you can push further commits to that branch, Github will automatically add them to an open pull request.</p><h3 id="donations¶" tabindex="-1">Donations¶ <a class="header-anchor" href="#donations¶" aria-label="Permalink to &quot;Donations¶&quot;">​</a></h3><p>The OVMS is a non-profit community project. Hardware production and service can normally be financed by sales, but some things (e.g. prototype development and certifications) need extra money. To help the project, you can make a donation on the OVMS website: <a href="https://www.openvehicles.com/forum" target="_blank" rel="noreferrer">https://www.openvehicles.com/forum</a></p><p>Please also consider supporting the vehicle developers directly. Check out their web sites and support addresses for their respective donation channels.</p><p><strong>Thank you!</strong></p><h3 id="license¶" tabindex="-1">License¶ <a class="header-anchor" href="#license¶" aria-label="Permalink to &quot;License¶&quot;">​</a></h3><p>The project includes some third party libraries and components to which their respective licenses apply, see component sources for details.</p><p>The project itself is published under the MIT license:</p><p>Copyright (c) 2011-2020 Open Vehicles</p><p>Permission is hereby granted, free of charge, to any person obtaining a copy of this software and associated documentation files (the “Software”), to deal in the Software without restriction, including without limitation the rights to use, copy, modify, merge, publish, distribute, sublicense, and/or sell copies of the Software, and to permit persons to whom the Software is furnished to do so, subject to the following conditions:</p><p>The above copyright notice and this permission notice shall be included in all copies or substantial portions of the Software.</p><p>THE SOFTWARE IS PROVIDED “AS IS”, WITHOUT WARRANTY OF ANY KIND, EXPRESS OR IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM, OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE SOFTWARE.</p><p>Software which uses other licenses will be annotated appropriately.</p>',41)])])}const u=t(i,[["render",a]]);export{m as __pageData,u as default};
